    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrdersWs error
        //
        //  {error: 'Insufficient margin to place order. asset=159'}
        //
        //  fetchOpenOrders
        //
        //     {
        //         "coin": "ETH",
        //         "limitPx": "2000.0",
        //         "oid": 3991946565,
        //         "origSz": "0.1",
        //         "side": "B",
        //         "sz": "0.1",
        //         "timestamp": 1704346468838
        //     }
        // fetchClosedorders
        //    {
        //        "cloid": null,
        //        "closedPnl": "0.0",
        //        "coin": "SOL",
        //        "crossed": true,
        //        "dir": "Open Long",
        //        "fee": "0.003879",
        //        "hash": "0x4a2647998682b7f07bc5040ab531e1011400f9a51bfa0346a0b41ebe510e8875",
        //        "liquidationMarkPx": null,
        //        "oid": "6463280784",
        //        "px": "110.83",
        //        "side": "B",
        //        "startPosition": "1.64",
        //        "sz": "0.1",
        //        "tid": "232174667018988",
        //        "time": "1709142268394"
        //    }
        //
        //  fetchOrder
        //
        //     {
        //         "order": {
        //             "children": [],
        //             "cloid": null,
        //             "coin": "ETH",
        //             "isPositionTpsl": false,
        //             "isTrigger": false,
        //             "limitPx": "2000.0",
        //             "oid": "3991946565",
        //             "orderType": "Limit",
        //             "origSz": "0.1",
        //             "reduceOnly": false,
        //             "side": "B",
        //             "sz": "0.1",
        //             "tif": "Gtc",
        //             "timestamp": "1704346468838",
        //             "triggerCondition": "N/A",
        //             "triggerPx": "0.0"
        //         },
        //         "status": "open",
        //         "statusTimestamp": "1704346468838"
        //     }
        //
        // createOrder
        //
        //     {
        //         "resting": {
        //             "oid": 5063830287
        //         }
        //     }
        //
        //     {
        //        "filled":{
        //           "totalSz":"0.1",
        //           "avgPx":"100.84",
        //           "oid":6195281425
        //        }
        //     }
        // frontendOrder
        // {
        //     "children": [],
        //     "cloid": null,
        //     "coin": "BLUR",
        //     "isPositionTpsl": false,
        //     "isTrigger": true,
        //     "limitPx": "0.5",
        //     "oid": 8670487141,
        //     "orderType": "Stop Limit",
        //     "origSz": "20.0",
        //     "reduceOnly": false,
        //     "side": "B",
        //     "sz": "20.0",
        //     "tif": null,
        //     "timestamp": 1715523663687,
        //     "triggerCondition": "Price above 0.6",
        //     "triggerPx": "0.6"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object error = this.safeString(order, "error");
        if (Helpers.isTrue(!Helpers.isEqual(error, null)))
        {
            Object finalOrder = order; // java req
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "info", finalOrder );
                put( "status", "rejected" );
            }});
        }
        Object entry = this.safeDictN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("order", "resting", "filled")));
        if (Helpers.isTrue(Helpers.isEqual(entry, null)))
        {
            entry = order;
        }
        Object filled = this.safeDict(order, "filled", new java.util.HashMap<String, Object>() {{}});
        Object coin = this.safeString(entry, "coin");
        Object marketId = null;
        if (Helpers.isTrue(!Helpers.isEqual(coin, null)))
        {
            marketId = this.coinToMarketId(coin);
        }
        if (Helpers.isTrue(Helpers.isEqual(this.safeString(entry, "id"), null)))
        {
            market = this.safeMarket(marketId, null);
        } else
        {
            market = this.safeMarket(marketId, market);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(entry, "timestamp");
        Object status = this.safeString2(order, "status", "ccxtStatus");
        order = this.omit(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("ccxtStatus")));
        Object side = this.safeString(entry, "side");
        if (Helpers.isTrue(!Helpers.isEqual(side, null)))
        {
            side = ((Helpers.isTrue((Helpers.isEqual(side, "A"))))) ? "sell" : "buy";
        }
        Object totalAmount = this.safeString2(entry, "origSz", "totalSz");
        Object remaining = this.safeString(entry, "sz");
        Object tif = this.safeStringUpper(entry, "tif");
        Object postOnly = null;
        if (Helpers.isTrue(!Helpers.isEqual(tif, null)))
        {
            postOnly = (Helpers.isEqual(tif, "ALO"));
        }
        Object triggerPx = ((Helpers.isTrue(this.safeBool(entry, "isTrigger")))) ? this.safeNumber(entry, "triggerPx") : null;
        final Object finalOrder = order;
        final Object finalEntry = entry;
        final Object finalTif = tif;
        final Object finalPostOnly = postOnly;
        final Object finalSide = side;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", finalOrder );
            put( "id", HyperliquidCore.this.safeString(finalEntry, "oid") );
            put( "clientOrderId", HyperliquidCore.this.safeString(finalEntry, "cloid") );
            put( "timestamp", timestamp );
            put( "datetime", HyperliquidCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", HyperliquidCore.this.safeInteger(finalOrder, "statusTimestamp") );
            put( "symbol", symbol );
            put( "type", HyperliquidCore.this.parseOrderType(HyperliquidCore.this.safeStringLower(finalEntry, "orderType")) );
            put( "timeInForce", finalTif );
            put( "postOnly", finalPostOnly );
            put( "reduceOnly", HyperliquidCore.this.safeBool(finalEntry, "reduceOnly") );
            put( "side", finalSide );
            put( "price", HyperliquidCore.this.safeString(finalEntry, "limitPx") );
            put( "triggerPrice", triggerPx );
            put( "amount", totalAmount );
            put( "cost", null );
            put( "average", HyperliquidCore.this.safeString(finalEntry, "avgPx") );
            put( "filled", HyperliquidCore.this.safeString(filled, "totalSz", Precise.stringSub(totalAmount, remaining)) );
            put( "remaining", remaining );
            put( "status", HyperliquidCore.this.parseOrderStatus(status) );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    public Object parseOrderStatus(Object status)
    {
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "triggered", "open" );
            put( "filled", "closed" );
            put( "open", "open" );
            put( "canceled", "canceled" );
            put( "rejected", "rejected" );
            put( "marginCanceled", "canceled" );
        }};
        if (Helpers.isTrue(((String)status).endsWith(((String)"Rejected"))))
        {
            return "rejected";
        }
        if (Helpers.isTrue(((String)status).endsWith(((String)"Canceled"))))
        {
            return "canceled";
        }
        return this.safeString(statuses, status, status);
    }

    public Object parseOrderType(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "stop limit", "limit" );
            put( "stop market", "market" );
        }};
        return this.safeString(statuses, status, status);
    }

