    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // {
        //     "time":1724762307531,
        //     "hash":"0x620a234a7e0eb7930575040f59482a01050058b0802163b4767bfd9033e77781",
        //     "delta":{
        //         "type":"accountClassTransfer",
        //         "usdc":"50.0",
        //         "toPerp":false
        //     }
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(item, "time");
        Object delta = this.safeDict(item, "delta", new java.util.HashMap<String, Object>() {{}});
        Object fee = null;
        Object feeCost = this.safeInteger(delta, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", "USDC" );
                put( "cost", finalFeeCost );
            }};
        }
        Object type = this.safeString(delta, "type");
        Object amount = this.safeString(delta, "usdc");
        final Object finalFee = fee;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", HyperliquidCore.this.safeString(item, "hash") );
            put( "direction", null );
            put( "account", null );
            put( "referenceAccount", HyperliquidCore.this.safeString(delta, "user") );
            put( "referenceId", HyperliquidCore.this.safeString(item, "hash") );
            put( "type", HyperliquidCore.this.parseLedgerEntryType(type) );
            put( "currency", null );
            put( "amount", HyperliquidCore.this.parseNumber(amount) );
            put( "timestamp", timestamp );
            put( "datetime", HyperliquidCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", finalFee );
        }}, currency);
    }

